#!/usr/bin/env bash
# evidence.sh — Evidence 决策助手 for 知乎 AI 自媒体博主.
# Auto-generated by cli_writer.py. Source: synthesis.md Section 2 (Playbook).
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="知乎 AI 自媒体博主"
TOPIC="Evidence"

usage() {
  cat <<EOF
evidence.sh — ${TOPIC} 决策助手 for ${INDUSTRY}

基于 7 条 playbook 规则的交互式决策评估。
你描述情景, 工具帮你判断哪条规则适用, 并给推荐。

USAGE:
  ./evidence.sh             # interactive
  ./evidence.sh --dry-run   # walk through but no file
  ./evidence.sh --json      # JSON to stdout
  ./evidence.sh --explain   # show backing playbook rules + mental models
  ./evidence.sh --help      # this message
EOF
}

explain() {
  cat <<'EOT'
这个决策助手把 Evidence 主题下的 playbook 规则组合成交互树。

基于 7 条规则:
  • 如果 开头用结论先行或反常识钩子 → 则 ：首段触发"然后呢？"。案例：答"你何时对深度学习失去信心"，霍华德式开篇直接给逆向判断定调，而非"这是个好问题，让我们
  • 如果 绑定第一现场身份做权威锚 → 则 ：一作解读/框架作者/亲历者。案例：丁霄汉论文中了同步发万字"一作解读"，身份始终"我是作者"，建立不可替代权威。evi
  • 如果 AI 出初稿 → 人工重写注入一手 + 过禁用词表 → 则 ：翻译即重写。案例：用 DeepSeek 搭论证框架，人工补"我实测三天"的一手 + 按 khazix-writer 禁
  • 如果 金句式标题 + 核心关键词前置 → 则 ：数字/反差/痛点/钩子。案例：丁霄汉"让 VGG 式模型再次伟大""越大越暴力涨点又高效"，比"关于 RepVGG 的
  • 如果 技术长文用代码块+流程图+公式，不堆配图 → 则 ：知乎差异点。案例：代码用 Carbon/ray.so 美化截图、架构让 DeepSeek 直出 mermaid 码进 
  • 如果 编号连载 / 系列化降单篇门槛 + 造追更 → 则 ：把读论文产品化。案例：hzwer `[大模型 09]…[58]` 编号连载、苏剑林"Transformer 升级之路"
  • 如果 发布前过两道闸：勾 AI 标识 + 朱雀自检 → 则 ：合规反获流量。案例：用过 AI（含润色）即勾"AI 生成"标签，发前朱雀查 AI 率评估限流风险；不标＝限流/处罚。e

来源: synthesis.md Section 2.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a RULE_CONDITIONS=(
  "开头用结论先行或反常识钩子"
  "绑定第一现场身份做权威锚"
  "AI 出初稿 → 人工重写注入一手 + 过禁用词表"
  "金句式标题 + 核心关键词前置"
  "技术长文用代码块+流程图+公式，不堆配图"
  "编号连载 / 系列化降单篇门槛 + 造追更"
  "发布前过两道闸：勾 AI 标识 + 朱雀自检"
)
declare -a RULE_ACTIONS=(
  "：首段触发\"然后呢？\"。案例：答\"你何时对深度学习失去信心\"，霍华德式开篇直接给逆向判断定调，而非\"这是个好问题，让我们…\"。evidence: [T03-S025, T01-S036]"
  "：一作解读/框架作者/亲历者。案例：丁霄汉论文中了同步发万字\"一作解读\"，身份始终\"我是作者\"，建立不可替代权威。evidence: [T01-S002, T01-S006]"
  "：翻译即重写。案例：用 DeepSeek 搭论证框架，人工补\"我实测三天\"的一手 + 按 khazix-writer 禁用词表删\"说白了/本质上/赋能\"。evidence: [T01-S028, T01-S046]"
  "：数字/反差/痛点/钩子。案例：丁霄汉\"让 VGG 式模型再次伟大\"\"越大越暴力涨点又高效\"，比\"关于 RepVGG 的一些思考\"点击高一截。evidence: [T03-S026, T01-S006]"
  "：知乎差异点。案例：代码用 Carbon/ray.so 美化截图、架构让 DeepSeek 直出 mermaid 码进 mermaid.live、公式靠 mdnice 渲染——比 AI 生图更刚需。evidence: [T02-S011, T02-S014]"
  "：把读论文产品化。案例：hzwer \`[大模型 09]…[58]\` 编号连载、苏剑林\"Transformer 升级之路\"系列，前后互引形成知识地图、读者追更。evidence: [T01-S041, T01-S002]"
  "：合规反获流量。案例：用过 AI（含润色）即勾\"AI 生成\"标签，发前朱雀查 AI 率评估限流风险；不标＝限流/处罚。evidence: [T02-S018, T03-S025]"
)
declare -a APPLIED_RULES=()

ms_section "${INDUSTRY} · ${TOPIC} 决策评估"
ms_info "本工具基于 ${#RULE_CONDITIONS[@]} 条 playbook 规则评估你的情景。"
echo

ms_prompt "请描述当前情景 (空行结束):"
echo
SITUATION="$(ms_read_multiline)"

for i in "${!RULE_CONDITIONS[@]}"; do
  ms_section "Rule $((i+1))/${#RULE_CONDITIONS[@]}"
  echo "适用情景: ${RULE_CONDITIONS[$i]}"
  echo "推荐做法: ${RULE_ACTIONS[$i]}"
  if ms_confirm "这条规则 fit 你当前情景吗?"; then
    APPLIED_RULES+=("$((i+1))")
    ms_ok "适用 rule $((i+1))"
  fi
done

ms_buffer_append "# ${INDUSTRY} — ${TOPIC} 决策报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## 情景"
ms_buffer_append ""
ms_buffer_append "$SITUATION"
ms_buffer_append ""
ms_buffer_append "## 适用规则"
ms_buffer_append ""
if [[ ${#APPLIED_RULES[@]} -eq 0 ]]; then
  ms_buffer_append "(无适用 playbook 规则 — 此情景在已知 OS 之外, 建议回到 SKILL.md 心智模型层重新分析)"
else
  for ridx in "${APPLIED_RULES[@]}"; do
    i=$((ridx-1))
    ms_buffer_append "- **情景**: ${RULE_CONDITIONS[$i]} → **做法**: ${RULE_ACTIONS[$i]}"
  done
fi
ms_buffer_append ""

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "topic" "${TOPIC}" \
    "situation" "${SITUATION}" \
    "applied_rules_count" "${#APPLIED_RULES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "evidence-decision"
fi
